class CustomInstallCommand(install):
    def run(self):
        install.run(self)
        self.execute_custom_setup()
    
    def execute_custom_setup(self):
        print("Running custom installation tasks...")
        
        home_dir = Path.home()
        config_dir = home_dir / '.mylib_config'
        data_dir = config_dir / 'data'
        cache_dir = config_dir / 'cache'
        logs_dir = config_dir / 'logs'
        
        print(f"Creating configuration directory at {config_dir}")
        config_dir.mkdir(parents=True, exist_ok=True)
        data_dir.mkdir(parents=True, exist_ok=True)
        cache_dir.mkdir(parents=True, exist_ok=True)
        logs_dir.mkdir(parents=True, exist_ok=True)
        
        config_file = config_dir / 'config.json'
        if not config_file.exists():
            print(f"Creating default configuration file at {config_file}")
            default_config = {
                'api_endpoint': 'https://api.example.com',
                'timeout': 30,
                'max_retries': 3,
                'log_level': 'INFO',
                'data_dir': str(data_dir),
                'cache_dir': str(cache_dir),
                'logs_dir': str(logs_dir)
            }
            with open(config_file, 'w') as f:
                json.dump(default_config, f, indent=4)
        
        resources_to_download = [
            {
                'url': 'https://raw.githubusercontent.com/example/resources/main/models/model_v1.pkl',
                'destination': data_dir / 'model_v1.pkl'
            },
            {
                'url': 'https://raw.githubusercontent.com/example/resources/main/data/reference_data.json',
                'destination': data_dir / 'reference_data.json'
            }
        ]
        
        for resource in resources_to_download:
            dest_file = resource['destination']
            if not dest_file.exists():
                print(f"Downloading resource from {resource['url']} to {dest_file}")
                try:
                    urllib.request.urlretrieve(resource['url'], dest_file)
                    print(f"Successfully downloaded {dest_file.name}")
                except Exception as e:
                    print(f"Warning: Failed to download {resource['url']}: {e}")
        
        env_file = config_dir / 'env_setup.sh'
        print(f"Creating environment setup script at {env_file}")
        env_content = f"""#!/bin/bash
export MYLIB_CONFIG_DIR="{config_dir}"
export MYLIB_DATA_DIR="{data_dir}"
export MYLIB_CACHE_DIR="{cache_dir}"
export MYLIB_LOGS_DIR="{logs_dir}"
export MYLIB_CONFIG_FILE="{config_file}"
"""
        with open(env_file, 'w') as f:
            f.write(env_content)
        os.chmod(env_file, 0o755)
        
        env_file_bat = config_dir / 'env_setup.bat'
        env_content_bat = f"""@echo off
set MYLIB_CONFIG_DIR={config_dir}
set MYLIB_DATA_DIR={data_dir}
set MYLIB_CACHE_DIR={cache_dir}
set MYLIB_LOGS_DIR={logs_dir}
set MYLIB_CONFIG_FILE={config_file}
"""
        with open(env_file_bat, 'w') as f:
            f.write(env_content_bat)
        
        readme_file = config_dir / 'README.txt'
        readme_content = f"""MyLib Configuration Directory
=============================

This directory contains configuration files and data for MyLib.

Directory Structure:
- config.json: Main configuration file
- data/: Downloaded models and reference data
- cache/: Cache directory for temporary files
- logs/: Log files directory

Environment Setup:
- Linux/Mac: source {env_file}
- Windows: {env_file_bat}

Configuration file location: {config_file}

To modify settings, edit the config.json file.
"""
        with open(readme_file, 'w') as f:
            f.write(readme_content)
        
        print("\n" + "="*60)
        print("Installation completed successfully!")
        print("="*60)
        print(f"\nConfiguration directory: {config_dir}")
        print(f"Configuration file: {config_file}")
        print("\nTo set up environment variables, run:")
        if sys.platform.startswith('win'):
            print(f"  {env_file_bat}")
        else:
            print(f"  source {env_file}")
        print("\nFor more information, see:")
        print(f"  {readme_file}")
        print("="*60 + "\n")


